const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

let player = {
    x: canvas.width / 2,
    y: canvas.height / 2,
    speed: 200, // pixels per second
};

let lastTime = performance.now();
let deltaTime = 0;

function gameLoop() {
    const currentTime = performance.now();
    deltaTime = (currentTime - lastTime) / 1000; // Convert to seconds
    lastTime = currentTime;

    updatePlayerPosition(deltaTime);
    render();

    requestAnimationFrame(gameLoop);
}

function updatePlayerPosition(deltaTime) {
    const input = getPlayerInput(); // Assume this function safely retrieves input
    const distance = player.speed * deltaTime;

    if (input.up) player.y -= distance;
    if (input.down) player.y += distance;
    if (input.left) player.x -= distance;
    if (input.right) player.x += distance;

    // Boundary checks
    player.x = Math.max(0, Math.min(canvas.width, player.x));
    player.y = Math.max(0, Math.min(canvas.height, player.y));
}

function render() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = 'blue';
    ctx.fillRect(player.x, player.y, 20, 20); // Draw player as a square
}

